/**
 * Category API Service
 * Handles all category-related API operations for RelatedDataDef
 */

class CategoryApiService {
  constructor() {
    this.baseUrl = '/RelatedDataDef';
  }

  /**
   * Create a new category
   * @param {string} categoryName - Name of the category to create
   * @returns {Promise<Object>} API response
   */
  async createCategory(categoryName) {
    try {
      const response = await fetch(`${this.baseUrl}/EditCategory`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          editCategoryName: categoryName,
          editCategoryCode: '', // Empty for new category
          isAjax: 'true' // This tells the controller to return JSON instead of redirect
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      return result;
    } catch (error) {
      console.error('Error creating category:', error);
      return { success: false, error: error.message };
    }
  }

  /**
   * Update an existing category
   * @param {string} categoryName - New name for the category
   * @param {string} categoryCode - Code of the category to update
   * @returns {Promise<Object>} API response
   */
  async updateCategory(categoryName, categoryCode) {
    try {
      const response = await fetch(`${this.baseUrl}/EditCategory`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          editCategoryName: categoryName,
          editCategoryCode: categoryCode,
          isAjax: 'true' // This tells the controller to return JSON instead of redirect
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      return result;
    } catch (error) {
      console.error('Error updating category:', error);
      return { success: false, error: error.message };
    }
  }

  /**
   * Clone an existing category
   * @param {string} cloneCategoryName - Name for the new cloned category
   * @param {string} originalCategoryName - Name of the category to clone
   * @returns {Promise<Object>} API response
   */
  async cloneCategory(cloneCategoryName, originalCategoryName) {
    try {
      const response = await fetch(`${this.baseUrl}/CloneCategory`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          cloneCategoryName: cloneCategoryName,
          cloneCategory: originalCategoryName,
          isAjax: 'true' // This tells the controller to return JSON instead of redirect
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      return result;
    } catch (error) {
      console.error('Error cloning category:', error);
      return { success: false, error: error.message };
    }
  }

  /**
   * Delete a category
   * @param {string} categoryName - Name of the category to delete
   * @returns {Promise<Object>} API response
   */
  async deleteCategory(categoryName) {
    try {
      const response = await fetch(`${this.baseUrl}/PurgeCategory`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          purgeCategory: categoryName,
          isAjax: 'true' // This tells the controller to return JSON instead of redirect
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      return result;
    } catch (error) {
      console.error('Error deleting category:', error);
      return { success: false, error: error.message };
    }
  }

  /**
   * Check if category name is unique
   * @param {string} categoryName - Name to check
   * @returns {Promise<Object>} API response
   */
  async checkCategoryUnique(categoryName) {
    try {
      const response = await fetch(`${this.baseUrl}/CheckCategoryUnique`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          categoryName: categoryName
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      return { success: true, data: result };
    } catch (error) {
      console.error('Error checking category uniqueness:', error);
      return { success: false, error: error.message };
    }
  }
}

// Create and export singleton instance
const categoryApi = new CategoryApiService();
export default categoryApi;
