import React, { useState, useEffect, useCallback } from 'react';
import { 
  Box, 
  Paper, 
  Card, 
  CardContent, 
  IconButton,
  Alert,
  Checkbox,
  Menu,
  MenuItem,
  ListItemIcon,
  ListItemText,
  FormControl,
  InputLabel,
  Select,
  Typography,
  ButtonGroup,
  Button
} from '@mui/material';
import { 
  Add as AddIcon, 
  Refresh as RefreshIcon,
  MoreVert as MoreVertIcon,
  FindInPage as FindIcon,
  KeyboardArrowDown as ChevronDownIcon
} from '@mui/icons-material';
import EditIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Edit.js";
import CopyIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Copy.js";
import TrashIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Trash.js";
import SearchIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Search.js";
import FAWTypography from '../../FAWTypography';
import FAWSelect from '../../FAWSelect';
import FAWDropdown from '../../FAWDropdown';
import FAWButton from '../../FAWButton';
import FAWInput from '../../FAWInput';
import FAWToast from '../../FAWToast';
import FAWTooltip from '../../FAWTooltip';
import FAWTable from '../../FAWTable/FAWTable';
import FAWLoader from '../../FAWLoader';
import FieldEditorDrawer from './FieldEditorDrawer';
import FAWConfirmationDialog from '../../FAWConfirmationDialog';
import FAWErrorBoundary from '../../errorHandling/FAWErrorBoundary';
import AddCategoryDrawer from './AddCategoryDrawer';
import EditCategoryDrawer from './EditCategoryDrawer';
import CloneCategoryDrawer from './CloneCategoryDrawer';
import SearchFieldDrawer from './SearchFieldDrawer';
import categoryApi from '../services/categoryApi';
import dataApi from '../services/dataApi';

/**
 * RelatedDataDef Manager Component
 * Manages user-defined fields with categories, search, and CRUD operations
 */
const RelatedDataDefManager = (props = {}) => {
  const [selectedCategory, setSelectedCategory] = useState('');
  const [categories, setCategories] = useState([]);
  const [fields, setFields] = useState([]);
  const [fieldsError, setFieldsError] = useState(null);
  const [loading, setLoading] = useState(false);
  const [categoriesLoading, setCategoriesLoading] = useState(false);
  const [error, setError] = useState(null);
  const [fieldOptions, setFieldOptions] = useState({
    dataTypeOptions: [],
    domainOptions: []
  });
  const [fieldOptionsLoading, setFieldOptionsLoading] = useState(false);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [drawerFieldId, setDrawerFieldId] = useState(null);
  const [categoryMenuAnchor, setCategoryMenuAnchor] = useState(null);
  const [addCategoryDrawerOpen, setAddCategoryDrawerOpen] = useState(false);
  const [editCategoryDrawerOpen, setEditCategoryDrawerOpen] = useState(false);
  const [cloneCategoryDrawerOpen, setCloneCategoryDrawerOpen] = useState(false);
  const [deleteCategoryModalOpen, setDeleteCategoryModalOpen] = useState(false);
  const [deleteFieldModalOpen, setDeleteFieldModalOpen] = useState(false);
  const [fieldToDelete, setFieldToDelete] = useState(null);
  const [searchFieldDrawerOpen, setSearchFieldDrawerOpen] = useState(false);
  const [categoryFormData, setCategoryFormData] = useState({
    name: '',
    originalName: ''
  });
  const [categoryLoading, setCategoryLoading] = useState(false);
  const [toast, setToast] = useState({ 
    open: false, 
    message: '', 
    type: 'info'
  });

  const transformCategoriesData = (data) => {
    if (!Array.isArray(data)) {
      return [];
    }
    
    const transformed = data.map((item, index) => ({
      value: item.Code || item.Value || `category_${index}`,
      label: item.Meaning || item.Text || item.Name || `Category ${index + 1}`
    }));
    
    return transformed;
  };

  useEffect(() => {
    const loadFieldOptions = async () => {
      setFieldOptionsLoading(true);
      try {
        const optionsResult = await dataApi.getFieldOptions();
        if (optionsResult.success) {
          setFieldOptions({
            dataTypeOptions: optionsResult.dataTypeOptions || [],
            domainOptions: optionsResult.domainOptions || []
          });
        }
      } catch (error) {
        console.error('Error pre-loading field options:', error);
      } finally {
        setFieldOptionsLoading(false);
      }
    };

    loadFieldOptions();
  }, []);

  useEffect(() => {
    const fetchData = async () => {
      setCategoriesLoading(true);
      setError(null);
      setFieldsError(null);
      
      try {
        const categoriesResult = await dataApi.getCategories();
        
        if (categoriesResult.success) {
          const transformedCategories = transformCategoriesData(categoriesResult.categories);
          setCategories(transformedCategories);
        } else {
          throw new Error(categoriesResult.error || 'Failed to load categories');
        }
        
      } catch (error) {
        console.error('Error loading data:', error);
        setError(error.message);
      } finally {
        setCategoriesLoading(false);
      }
    };

    fetchData();
  }, []);

  useEffect(() => {
    if (!categoriesLoading && categories.length > 0 && !selectedCategory) {
      const firstCategory = categories[0].value;
      handleCategoryChange(firstCategory);
    }
  }, [categoriesLoading, categories, selectedCategory, handleCategoryChange]);

  const getCsrfToken = useCallback(() => {
    const token = document.querySelector('input[name="__RequestVerificationToken"]')?.value;
    return token;
  }, []);

  const showToast = useCallback((message, type = 'info') => {
    setToast({
      open: true,
      message,
      type
    });
  }, []);

  const handleCategoryChange = useCallback(async (category) => {
    if (!category) {
      setFields([]);
      setFieldsError(null);
      setSelectedCategory('');
      return;
    }
    
    setLoading(true);
    setError(null);
    setFieldsError(null);
    setSelectedCategory(category);

    try {
      const result = await dataApi.getFieldsByCategory(category);
      
      if (result.success) {
        setFields(result.fields || []);
        setFieldsError(null);
        setError(null);
      } else {
        const errorMessage = result.error || 'Failed to load fields';
        setFields([]);
        setFieldsError(errorMessage);
        showToast(`Failed to load fields: ${errorMessage}`, 'error');
      }
      
      setLoading(false);
    } catch (error) {
      console.error('Error loading fields:', error);
      const errorMessage = error.message || 'Failed to load fields';
      setError('Failed to load fields for category');
      setFields([]);
      setFieldsError(errorMessage);
      showToast(`Failed to load fields: ${errorMessage}`, 'error');
      setLoading(false);
    }
  }, [showToast]);

  const handleCategorySelect = useCallback(async (categoryCode) => {
    setSelectedCategory(categoryCode);
    setLoading(true);
    setError(null);
    
    try {
      const result = await dataApi.getFieldsByCategory(categoryCode);
      
      if (result.success) {
        setFields(result.fields);
      } else {
        throw new Error(result.error || 'Failed to load fields');
      }
    } catch (error) {
      console.error('Error loading fields:', error);
      setError(error.message);
    } finally {
      setLoading(false);
    }
  }, []);

  const handleAddCategory = useCallback(() => {
    setCategoryFormData({ name: '', originalName: '' });
    setAddCategoryDrawerOpen(true);
  }, []);

  const handleCategoryMenuOpen = useCallback((event) => {
    setCategoryMenuAnchor(event.currentTarget);
  }, []);

  const handleCategoryMenuClose = useCallback(() => {
    setCategoryMenuAnchor(null);
  }, []);

  const handleCategoryAction = useCallback((action) => {
    handleCategoryMenuClose();
    
    const selectedCategoryData = categories.find(cat => cat.value === selectedCategory);
    const categoryName = selectedCategoryData?.label || '';
    const categoryCode = selectedCategoryData?.value || '';
    
    switch (action) {
      case 'edit':
        setCategoryFormData({ 
          name: categoryName, 
          originalName: categoryCode
        });
        setEditCategoryDrawerOpen(true);
        break;
      case 'clone':
        setCategoryFormData({ 
          name: categoryName, 
          originalName: categoryCode
        });
        setCloneCategoryDrawerOpen(true);
        break;
      case 'delete':
        setDeleteCategoryModalOpen(true);
        break;
      case 'search':
        setSearchFieldDrawerOpen(true);
        break;
      default:
        break;
    }
  }, [categories, selectedCategory]);

  const handleFieldAction = useCallback((action, field) => {
    switch (action) {
      case 'edit':
        if (field && selectedCategory) {
          setDrawerFieldId(field.Id);
          setDrawerOpen(true);
        }
        break;
      case 'delete':
        setFieldToDelete(field);
        setDeleteFieldModalOpen(true);
        break;
      default:
        break;
    }
  }, [selectedCategory]);

  const handleAddField = useCallback(() => {
    if (!selectedCategory) {
      setToast({
        open: true,
        message: 'Please select a category first before adding a field.',
        type: 'warning'
      });
      return;
    }
    
    setDrawerFieldId(0);
    setDrawerOpen(true);
  }, [selectedCategory]);

  const handleCategoryFormSubmit = useCallback(async (action) => {
    if (!categoryFormData.name.trim()) {
      setToast({
        open: true,
        message: 'Category name is required',
        type: 'error'
      });
      return;
    }

    setCategoryLoading(true);

    try {
      let result;
      const categoryName = categoryFormData.name.trim();

      switch (action) {
        case 'add':
          result = await categoryApi.createCategory(categoryName);
          if (result.success) {
            setToast({
              open: true,
              message: 'Category created successfully',
              type: 'success'
            });
          } else {
            throw new Error(result.error || 'Failed to create category');
          }
          break;

        case 'update':
          const selectedCategoryData = categories.find(cat => cat.value === selectedCategory);
          const categoryCode = selectedCategoryData?.value;
          result = await categoryApi.updateCategory(categoryName, categoryCode);
          if (result.success) {
            setToast({
              open: true,
              message: 'Category updated successfully',
              type: 'success'
            });
          } else {
            throw new Error(result.error || 'Failed to update category');
          }
          break;

        case 'clone':
          const originalCategoryName = categoryFormData.originalName;
          result = await categoryApi.cloneCategory(categoryName, originalCategoryName);
          if (result.success) {
            setToast({
              open: true,
              message: 'Category cloned successfully',
              type: 'success'
            });
          } else {
            throw new Error(result.error || 'Failed to clone category');
          }
          break;

        default:
          throw new Error(`Unknown action: ${action}`);
      }
      
      setAddCategoryDrawerOpen(false);
      setEditCategoryDrawerOpen(false);
      setCloneCategoryDrawerOpen(false);
      setCategoryFormData({ name: '', originalName: '' });
      
      try {
        setCategoriesLoading(true);
        const categoriesResult = await dataApi.getCategories();
        if (categoriesResult.success) {
          const transformedCategories = transformCategoriesData(categoriesResult.categories);
          setCategories(transformedCategories);
        }
      } catch (error) {
        console.error('Error refreshing categories:', error);
      } finally {
        setCategoriesLoading(false);
      }
      
    } catch (error) {
      console.error(`Error ${action}ing category:`, error);
      const errorPrefix = `Failed to ${action} category:`;
      const errorMessage = error.message.startsWith(errorPrefix)
        ? error.message
        : `${errorPrefix} ${error.message}`;
      setToast({
        open: true,
        message: errorMessage,
        type: 'error'
      });
      setAddCategoryDrawerOpen(false);
      setEditCategoryDrawerOpen(false);
      setCloneCategoryDrawerOpen(false);
      setCategoryFormData({ name: '', originalName: '' });
    } finally {
      setCategoryLoading(false);
    }
  }, [categoryFormData, categories, selectedCategory]);

  const handleDeleteCategory = useCallback(async () => {
    setCategoryLoading(true);

    try {
      const selectedCategoryData = categories.find(cat => cat.value === selectedCategory);
      const categoryCode = selectedCategoryData?.value;
      const categoryName = selectedCategoryData?.label;
      
      if (!categoryCode) {
        throw new Error('Category not found');
      }

      const result = await categoryApi.deleteCategory(categoryCode);
      
      if (result.success) {
        setToast({
          open: true,
          message: 'Category deleted successfully',
          type: 'success'
        });
        
        try {
          setCategoriesLoading(true);
          const categoriesResult = await dataApi.getCategories();
          if (categoriesResult.success) {
            const transformedCategories = transformCategoriesData(categoriesResult.categories);
            setCategories(transformedCategories);
            
            if (!transformedCategories.find(cat => cat.value === selectedCategory)) {
              setSelectedCategory(transformedCategories.length > 0 ? transformedCategories[0].value : '');
            }
          }
        } catch (error) {
          console.error('Error refreshing categories after delete:', error);
        } finally {
          setCategoriesLoading(false);
        }
        
        setDeleteCategoryModalOpen(false);
      } else {
        throw new Error(result.error || 'Failed to delete category');
      }
      
    } catch (error) {
      console.error('Error deleting category:', error);
      const errorPrefix = 'Failed to delete category:';
      const errorMessage = error.message.startsWith(errorPrefix)
        ? error.message
        : `${errorPrefix} ${error.message}`;
      setToast({
        open: true,
        message: errorMessage,
        type: 'error'
      });
      setDeleteCategoryModalOpen(false); // Close modal on error
    } finally {
      setCategoryLoading(false);
    }
  }, [selectedCategory, categories]);

  const handleDeleteField = useCallback(async () => {
    if (!fieldToDelete || !selectedCategory) {
      return;
    }

    try {
      const getCsrfToken = () => document.querySelector('input[name="__RequestVerificationToken"]')?.value || null;
      
      const headers = { 
        'Content-Type': 'application/json'
      };
      const token = getCsrfToken();
      if (token) headers['RequestVerificationToken'] = token;

      const response = await fetch('/RelatedDataDef/PurgeFieldApi', {
        method: 'POST',
        headers: headers,
        body: JSON.stringify({ 
          purgeId: fieldToDelete.Id,
          category: selectedCategory
        })
      });

      if (!response.ok) {
        throw new Error(`Delete failed with status: ${response.status}`);
      }

      const result = await response.json();
      
      if (result && result.success === true) {
        setDeleteFieldModalOpen(false);
        const deletedFieldName = fieldToDelete?.Name || 'Field';
        setFieldToDelete(null);
        
        setToast({
          open: true,
          message: result.message || `${deletedFieldName} deleted successfully`,
          type: 'success'
        });
        
        try {
          await handleCategoryChange(selectedCategory);
        } catch (refreshError) {
          console.error('Error refreshing fields after delete:', refreshError);
        }
      } else {
        throw new Error(result?.message || 'Failed to delete field');
      }
    } catch (error) {
      console.error('Error deleting field:', error);
      setToast({
        open: true,
        message: `Failed to delete field: ${error.message}`,
        type: 'error'
      });
    }
  }, [fieldToDelete, selectedCategory, handleCategoryChange]);

  const handleFieldActiveToggle = useCallback((field, checked) => {
    // Implement toggle logic
  }, []);

  return (
    <FAWErrorBoundary>
      <Box className="related-data-def-manager" sx={{ 
        //p: 3, 
        //backgroundColor: '#fafafa',
        minHeight: '100vh',
        //fontFamily: 'Roboto, sans-serif'
      }}>
        {/* Header */}
        <Box className="manager-header" sx={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center',
          mb: 3
        }}>
          <FAWTypography 
            className="manager-title"
            variant="h4" 
            sx={{ 
              fontWeight: 'bold',
              color: '#333',
              fontSize: '2rem'
            }}
          >
            Manage Additional Fields
          </FAWTypography>
          
          <FAWButton
            className="add-category-button"
            variant="contained"
            color="primary"
            startIcon={<AddIcon />}
            onClick={handleAddCategory}
          >
            Add New Category
          </FAWButton>
        </Box>

        {/* Categories Section */}
        <Paper className="categories-section" sx={{ 
          display: 'flex',
          padding: '24px',
          alignItems: 'flex-end',
          gap: '24px',
          flex: '1 0 0',
          borderRadius: '12px',
          backgroundColor: '#F0F1F3',
          //mb: 3,
          boxShadow: 'none !important'
        }}> 
          <Box className="category-selection-container" 
            sx={{ 
              display: 'flex', 
              alignItems: 'end', 
              justifyContent: 'space-between', 
              width: '100%', 
              gap: 2 
            }}
          >
            <Box className="category-dropdown-container" sx={{ flex: '0 0 auto', width: '24em !important' }}>
              <FAWDropdown
                className="category-select"
                label="Categories"
                options={categories}
                value={selectedCategory}
                onChange={(newValue, event) => {
                  handleCategoryChange(newValue?.value || '');
                }}
                disabled={categoriesLoading}
                loading={categoriesLoading}
                searchable={false}
                placeholder={categoriesLoading ? "Loading categories..." : "Select a category..."}
                sx={{ width: '40em', backgroundColor: '#FFFFFF !important' }}
              />
            </Box>
            
            <Box 
              className="manage-category-button-group"
              sx={{
                display: 'flex',
                alignItems: 'center',
                gap: '0',
                marginLeft: 'auto'
              }}
            >
              <Button
                className="manage-category-button"
                onClick={handleCategoryMenuOpen}
                disabled={!selectedCategory}
                sx={{
                  display: 'flex',
                  padding: '8px 12px',
                  justifyContent: 'center',
                  alignItems: 'center',
                  gap: '8px',
                  borderRadius: '12px 0 0 12px',
                  border: '1px solid #282E37',
                  color: '#282E37',
                  backgroundColor: 'transparent',
                  textTransform: 'none',
                  '&:hover': {
                    backgroundColor: '#f5f5f5',
                    borderColor: '#282E37'
                  },
                  '&:disabled': {
                    color: '#ccc',
                    borderColor: '#ccc',
                    backgroundColor: 'transparent'
                  }
                }}
              >
                Manage Category
              </Button>
              <Button
                className="manage-category-dropdown-button"
                onClick={handleCategoryMenuOpen}
                disabled={!selectedCategory}
                sx={{
                  display: 'flex',
                  padding: '8px',
                  ml: 0.25,
                  justifyContent: 'center',
                  alignItems: 'center',
                  gap: '0',
                  borderRadius: '0 12px 12px 0',
                  border: '1px solid #282E37',
                  color: '#282E37',
                  backgroundColor: 'transparent',
                  minWidth: 'auto',
                  textTransform: 'none',
                  '&:hover': {
                    backgroundColor: '#f5f5f5',
                    borderColor: '#282E37'
                  },
                  '&:disabled': {
                    color: '#ccc',
                    borderColor: '#ccc',
                    backgroundColor: 'transparent'
                  }
                }}
              >
                <ChevronDownIcon />
              </Button>
            </Box>
          </Box>
        </Paper>


        {/* Fields Table using FAWTable */}
        {/* <Paper className="fields-table-section" sx={{ backgroundColor: 'white', position: 'relative' }}> */}
          {/* Show error banner if there's an error and we have fields (so error is visible above grid) */}
          {fieldsError && fields.length > 0 && (
            <Box sx={{ p: 2, backgroundColor: '#ffebee', borderBottom: '1px solid #ef5350' }}>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <FAWTypography variant="body2" color="error">
                  ⚠️ Failed to refresh fields: {fieldsError}
                </FAWTypography>
                <FAWTooltip title="Retry">
                  <IconButton
                    aria-label="Retry"
                    size="small"
                    onClick={() => handleCategoryChange(selectedCategory)}
                    sx={{ ml: 2 }}
                  >
                    <RefreshIcon fontSize="small" />
                  </IconButton>
                </FAWTooltip>
              </Box>
            </Box>
          )}
          
          <Box sx={{ pb: 2 }}>
            <FAWTable
              columns={[
                {
                  field: 'Name',
                  headerName: 'Name',
                  minWidth: 200,
                  maxWidth: 500,
                  flex: 1,
                  sortable: true,
                  filterable: true,
                  hideable: false,
                  renderCell: (params) => (
                    <FAWTypography variant="body2" sx={{ fontWeight: 'medium' }}>
                      {params.value || '—'}
                    </FAWTypography>
                  )
                },
                {
                  field: 'Description',
                  headerName: 'Description',
                  minWidth: 200,
                  maxWidth: 600,
                  flex: 1,
                  sortable: true,
                  filterable: true,
                  renderCell: (params) => (
                    <FAWTypography variant="body2" color="text.secondary">
                      {params.value || '—'}
                    </FAWTypography>
                  )
                },
                {
                  field: 'DataTypeName',
                  headerName: 'Data Type',
                  minWidth: 120,
                  maxWidth: 200,
                  flex: 0.5,
                  sortable: true,
                  filterable: true,
                  renderCell: (params) => (
                    <FAWTypography variant="body2" color="text.secondary">
                      {params.value || 'Unknown'}
                    </FAWTypography>
                  )
                },
                {
                  field: 'Active',
                  headerName: 'Active',
                  minWidth: 100,
                  maxWidth: 150,
                  flex: 0.5,
                  sortable: false,
                  filterable: false,
                  type: 'checkbox',
                  editable: true,
                  renderCell: (params) => {
                    const field = params.row;
                    return (
                      <Checkbox
                        checked={field.Active || false}
                        onChange={(e) => handleFieldActiveToggle(field, e.target.checked)}
                        size="small"
                      />
                    );
                  }
                }
              ]}
              rows={loading && !categoriesLoading ? [] : fields.map((field, index) => ({
                ...field,
                id: field.Id || field.id || index
              }))}
              actions={[
                {
                  icon: 'edit',
                  onClick: (row) => handleFieldAction('edit', row),
                  tooltip: 'Edit Field'
                },
                {
                  icon: 'delete',
                  onClick: (row) => handleFieldAction('delete', row),
                  tooltip: 'Delete Field'
                }
              ]}
              showSearch={true}
              searchPlaceholder="Search by any field"
              showToolbar={true}
              showExport={true}
              showColumns={true}
              showFilter={true}
              showPagination={true}
              defaultPageSize={10}
              pageSizeOptionsOverride={[10, 25, 50, 100]}
              enableMultiSelect={false}
              autoHeight={true}
              loading={loading && !categoriesLoading}
              bulkActions={[
                {
                  label: 'Add Field',
                  onClick: () => handleAddField(),
                  alwaysEnabled: true,
                  disabled: !selectedCategory
                }
              ]}
              emptyStateTitle="No data available"
              emptyStateMessage="There are currently no fields defined for this category."
            />
          </Box>
        {/* </Paper> */}

        {/* Category Management Menu */}
        <Menu
          className="category-management-menu"
          anchorEl={categoryMenuAnchor}
          open={Boolean(categoryMenuAnchor)}
          onClose={handleCategoryMenuClose}
          slotProps={{
            paper: {
              sx: {
                borderRadius: 1,
                boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
                minWidth: 180
              }
            }
          }}
        >
          <MenuItem className="edit-category-menu-item" onClick={() => handleCategoryAction('edit')}>
            <ListItemIcon>
              <EditIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText sx={{ fontSize: '16px' }}>Edit</ListItemText>
          </MenuItem>
          <MenuItem className="clone-category-menu-item" onClick={() => handleCategoryAction('clone')}>
            <ListItemIcon>
              <CopyIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText sx={{ fontSize: '16px' }}>Clone</ListItemText>
          </MenuItem>
          <MenuItem className="delete-category-menu-item" onClick={() => handleCategoryAction('delete')}>
            <ListItemIcon>
              <TrashIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText sx={{ fontSize: '16px' }}>Delete</ListItemText>
          </MenuItem>
          <MenuItem className="search-category-menu-item" onClick={() => handleCategoryAction('search')}>
            <ListItemIcon>
              <SearchIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText sx={{ fontSize: '16px' }}>Search</ListItemText>
          </MenuItem>
        </Menu>


        {/* Error Display */}
        {error && (
          <Alert className="error-alert" severity="error" sx={{ mt: 2 }}>
            {error}
          </Alert>
        )}

        {/* Add Category Drawer */}
        <AddCategoryDrawer
          className="add-category-drawer"
          open={addCategoryDrawerOpen}
          onClose={() => setAddCategoryDrawerOpen(false)}
          categoryFormData={categoryFormData}
          onFormDataChange={setCategoryFormData}
          onSubmit={() => handleCategoryFormSubmit('add')}
          loading={categoryLoading}
        />

        {/* Edit Category Drawer */}
        <EditCategoryDrawer
          className="edit-category-drawer"
          open={editCategoryDrawerOpen}
          onClose={() => setEditCategoryDrawerOpen(false)}
          categoryFormData={categoryFormData}
          onFormDataChange={setCategoryFormData}
          onSubmit={() => handleCategoryFormSubmit('update')}
          loading={categoryLoading}
        />

        {/* Clone Category Drawer */}
        <CloneCategoryDrawer
          className="clone-category-drawer"
          open={cloneCategoryDrawerOpen}
          onClose={() => setCloneCategoryDrawerOpen(false)}
          categoryFormData={categoryFormData}
          onFormDataChange={setCategoryFormData}
          onSubmit={() => handleCategoryFormSubmit('clone')}
          loading={categoryLoading}
        />

        {/* Delete Category Confirmation Dialog */}
        <FAWConfirmationDialog
          className="delete-category-confirmation-dialog"
          open={deleteCategoryModalOpen}
          title="Delete Category"
          message={`Are you sure you want to delete the category "${categories.find(cat => cat.value === selectedCategory)?.label}"? This action cannot be undone.`}
          onConfirm={handleDeleteCategory}
          onCancel={() => setDeleteCategoryModalOpen(false)}
          confirmText="Delete"
          cancelText="Cancel"
          severity="error"
          maxWidth="sm"
        />

        {/* Delete Field Confirmation Dialog */}
        <FAWConfirmationDialog
          className="delete-field-confirmation-dialog"
          open={deleteFieldModalOpen}
          title="Delete Field"
          message={fieldToDelete ? `Are you sure you want to delete the field "${fieldToDelete.Name}"? This action cannot be undone.` : ''}
          onConfirm={handleDeleteField}
          onCancel={() => {
            setDeleteFieldModalOpen(false);
            setFieldToDelete(null);
          }}
          confirmText="Delete"
          cancelText="Cancel"
          severity="error"
          maxWidth="sm"
        />

        {/* Field Editor Drawer (direct React) */}
        <FieldEditorDrawer
          open={drawerOpen}
          onClose={() => {
            setDrawerOpen(false);
            setDrawerFieldId(null); // Reset drawer field ID on close
          }}
          fieldId={drawerFieldId}
          category={selectedCategory}
          dataTypeOptions={fieldOptions.dataTypeOptions}
          domainOptions={fieldOptions.domainOptions}
          optionsLoading={fieldOptionsLoading}
          existingFields={fields}
          onSave={async (formData) => {
            if (selectedCategory) {
              try {
                await handleCategoryChange(selectedCategory);
                setToast({
                  open: true,
                  message: 'Field saved successfully',
                  type: 'success'
                });
              } catch (refreshError) {
                console.error('Error refreshing fields after save:', refreshError);
                setToast({
                  open: true,
                  message: 'Field saved successfully, but failed to refresh the list',
                  type: 'warning'
                });
              }
            }
            setDrawerFieldId(null);
          }}
        />

        {/* Search Field Drawer */}
        <SearchFieldDrawer
          className="search-field-drawer"
          open={searchFieldDrawerOpen}
          onClose={() => setSearchFieldDrawerOpen(false)}
          categoryName={categories.find(cat => cat.value === selectedCategory)?.label}
          onCategorySelect={handleCategorySelect}
        />

        {/* Toast Notifications */}
        <FAWToast
          className="toast-notifications"
          open={toast.open}
          message={toast.message}
          type={toast.type}
          showCloseButton={true}
          position="top-right"
          onClose={() => setToast(prev => ({ ...prev, open: false }))}
        />
      </Box>
    </FAWErrorBoundary>
  );
};

export default RelatedDataDefManager;
