import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Box, List, ListItem, ListItemText, Typography, Alert } from '@mui/material';
import { Search as SearchIcon } from '@mui/icons-material';
import FAWDrawer from '../../FAWDrawer';
import FAWTypography from '../../FAWTypography';
import FAWInput from '../../FAWInput';
import dataApi from '../services/dataApi';

/**
 * SearchFieldDrawer Component
 * Drawer for searching additional fields by term and selecting categories
 * Matches the exact UI design from the image
 */
const SearchFieldDrawer = ({
  open,
  onClose,
  categoryName,
  onCategorySelect
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [error, setError] = useState(null);
  
  // Debouncing setup
  const debounceTimeoutRef = useRef(null);
  const DEBOUNCE_DELAY = 500; // 500ms delay

  // Debounced search effect
  useEffect(() => {
    // Clear previous timeout
    if (debounceTimeoutRef.current) {
      clearTimeout(debounceTimeoutRef.current);
    }

    // If search term is empty, clear results immediately
    if (!searchTerm.trim()) {
      setSearchResults([]);
      setError(null);
      return;
    }

    // Set up new timeout for debounced search
    debounceTimeoutRef.current = setTimeout(() => {
      performSearch(searchTerm.trim());
    }, DEBOUNCE_DELAY);

    // Cleanup function
    return () => {
      if (debounceTimeoutRef.current) {
        clearTimeout(debounceTimeoutRef.current);
      }
    };
  }, [searchTerm]);

  // Perform the actual search
  const performSearch = useCallback(async (term) => {
    if (!term.trim()) {
      setError('Please enter a search term');
      return;
    }

    setSearching(true);
    setError(null);
    setSearchResults([]);

    try {
      const result = await dataApi.searchCategoriesByTerm(term);
      
      if (result.success) {
        setSearchResults(result.categories);
      } else {
        setError(result.error || 'Search failed');
      }
    } catch (error) {
      console.error('SearchFieldDrawer - Search error:', error);
      setError(error.message);
    } finally {
      setSearching(false);
    }
  }, []);

  // Manual search trigger (for button click)
  const handleSearch = useCallback(() => {
    // Clear any pending debounced search
    if (debounceTimeoutRef.current) {
      clearTimeout(debounceTimeoutRef.current);
    }
    
    // Perform search immediately
    performSearch(searchTerm.trim());
  }, [searchTerm, performSearch]);

  // Handle category selection
  const handleCategoryClick = useCallback((category) => {
    onCategorySelect(category.Category);
    onClose();
  }, [onCategorySelect, onClose]);

  // Handle drawer close
  const handleClose = useCallback(() => {
    setSearchTerm('');
    setSearchResults([]);
    setError(null);
    onClose();
  }, [onClose]);

  // Handle Enter key press (immediate search)
  const handleKeyPress = useCallback((event) => {
    if (event.key === 'Enter') {
      handleSearch();
    }
  }, [handleSearch]);

  return (
    <FAWDrawer
      open={open}
      onClose={handleClose}
      title="Find Additional Field"
      anchor="right"
      width={400}
      actions={[
        {
          text: 'Cancel',
          variant: 'outlined',
          onClick: handleClose
        },
        {
          text: 'Clone',
          variant: 'contained',
          onClick: handleSearch,
          disabled: searching || !searchTerm.trim()
        }
      ]}
    >
      <Box sx={{ p: 3 }}>
        {/* Selected Category Display */}
        <FAWTypography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
          Selected category: {categoryName}
        </FAWTypography>
        
        {/* Search Input */}
        <FAWInput
          label="Name"
          required
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          placeholder="Keyword"
          fullWidth
          startIcon={<SearchIcon />}
          onKeyPress={handleKeyPress}
          sx={{ mb: 2 }}
          labelSx={{ fontSize: '14px', fontWeight: 500 }}
        />
        
        {/* Show debounced search indicator */}
        {searchTerm && !searching && (
          <FAWTypography variant="caption" color="text.secondary" sx={{ mb: 1, display: 'block' }}>
            Search will start automatically as you type...
          </FAWTypography>
        )}

        {/* Error Display */}
        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        {/* Instructions */}
        <FAWTypography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
          Click a category to navigate to it.
        </FAWTypography>

        {/* Search Results */}
        {searchResults.length > 0 ? (
          <Box>
            <FAWTypography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Found in categories:
            </FAWTypography>
            
            <Box sx={{ 
              maxHeight: 300, 
              overflowY: 'auto',
              border: '1px solid #e0e0e0',
              borderRadius: 1
            }}>
              <List dense>
                {searchResults.map((category, index) => (
                  <ListItem
                    key={index}
                    button
                    onClick={() => handleCategoryClick(category)}
                    sx={{
                      '&:hover': {
                        backgroundColor: '#f5f5f5'
                      }
                    }}
                  >
                    <ListItemText
                      primary={category.CategoryName}
                      sx={{
                        '& .MuiListItemText-primary': {
                          color: '#4c9be3',
                          cursor: 'pointer'
                        }
                      }}
                    />
                  </ListItem>
                ))}
              </List>
            </Box>
          </Box>
        ) : searchTerm && !searching && !error ? (
          <Alert severity="warning">
            No category found
          </Alert>
        ) : null}
      </Box>
    </FAWDrawer>
  );
};

export default SearchFieldDrawer;