import React from 'react';
import { Box } from '@mui/material';
import FAWDrawer from '../../FAWDrawer';
import FAWInput from '../../FAWInput';
import FAWLoader from '../../FAWLoader';

/**
 * AddCategoryDrawer Component
 * Drawer for adding new categories
 */
const AddCategoryDrawer = ({
  open,
  onClose,
  categoryFormData,
  onFormDataChange,
  onSubmit,
  loading = false
}) => {
  return (
    <FAWDrawer
      open={open}
      onClose={onClose}
      title="Add New Category"
      anchor="right"
      width={400}
      actions={[
        {
          text: 'Cancel',
          variant: 'outlined',
          onClick: onClose
        },
        {
          text: 'Add',
          variant: 'contained',
          onClick: onSubmit,
          disabled: loading
        }
      ]}
    >
      <Box sx={{ p: 3, position: 'relative' }}>
        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: 200 }}>
            <FAWLoader label="Creating category..." inline={false} />
          </Box>
        ) : (
          <FAWInput
            label="Name"
            required
            value={categoryFormData.name}
            onChange={(e) => onFormDataChange({ ...categoryFormData, name: e.target.value })}
            placeholder="Enter category name"
            fullWidth
            disabled={loading}
            labelSx={{ fontSize: '14px', fontWeight: 500 }}
          />
        )}
      </Box>
    </FAWDrawer>
  );
};

export default AddCategoryDrawer;
