import React from 'react';
import { Box } from '@mui/material';
import FAWDrawer from '../../FAWDrawer';
import FAWTypography from '../../FAWTypography';
import FAWInput from '../../FAWInput';
import FAWLoader from '../../FAWLoader';

/**
 * CloneCategoryDrawer Component
 * Drawer for cloning existing categories
 */
const CloneCategoryDrawer = ({
  open,
  onClose,
  categoryFormData,
  onFormDataChange,
  onSubmit,
  loading = false
}) => {
  return (
    <FAWDrawer
      open={open}
      onClose={onClose}
      title="Clone Category"
      anchor="right"
      width={400}
      actions={[
        {
          text: 'Cancel',
          variant: 'outlined',
          color: 'inherit',
          onClick: onClose
        },
        {
          text: 'Clone',
          variant: 'contained',
          color: 'primary',
          onClick: onSubmit,
          disabled: loading
        }
      ]}
    >
      <Box sx={{ p: 3, position: 'relative' }}>
        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: 200 }}>
            <FAWLoader label="Cloning category..." inline={false} />
          </Box>
        ) : (
          <>
            <FAWTypography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
              Selected category: {categoryFormData.originalName}
            </FAWTypography>
            
            <FAWInput
              label="Name"
              required
              value={categoryFormData.name}
              onChange={(e) => onFormDataChange({ ...categoryFormData, name: e.target.value })}
              placeholder="Enter new category name"
              fullWidth
              disabled={loading}
              labelSx={{ fontSize: '14px', fontWeight: 500 }}
            />
          </>
        )}
      </Box>
    </FAWDrawer>
  );
};

export default CloneCategoryDrawer;
