/**
 * Data API Service for RelatedDataDef
 * Uses existing controller methods to fetch data
 */
class DataApiService {
  constructor() {
    this.baseUrl = '/RelatedDataDef';
  }

  /**
   * Get all categories using existing GetOptionsForDomainCode method
   * @returns {Promise<Object>} API response with categories
   */
  async getCategories() {
    try {
      // Use the new separate API endpoint
      const response = await fetch(`${this.baseUrl}/GetCategoriesApi`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        }
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      
      if (result.success) {
        return { success: true, categories: result.categories };
      } else {
        throw new Error(result.error || 'Failed to get categories');
      }
    } catch (error) {
      console.error('Error getting categories:', error);
      return { success: false, error: error.message };
    }
  }


  /**
   * Get related data definitions by category using new API endpoint
   * @param {string} category - Category code
   * @returns {Promise<Object>} API response with fields
   */
  async getFieldsByCategory(category) {
    try {
      const response = await fetch(`${this.baseUrl}/GetFieldsByCategoryApi`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          category: category
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      
      if (result.success) {
        return { success: true, fields: result.fields };
      } else {
        throw new Error(result.error || 'Failed to get fields by category');
      }
    } catch (error) {
      console.error('Error getting fields for category:', error);
      return { success: false, error: error.message };
    }
  }

  /**
   * Search categories by term using new API endpoint
   * @param {string} term - Search term
   * @returns {Promise<Object>} API response with matching categories
   */
  async searchCategoriesByTerm(term) {
    try {
      const response = await fetch(`${this.baseUrl}/GetCategoryByTermApi`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          term: term
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      
      if (result.success) {
        return { success: true, categories: result.categories };
      } else {
        throw new Error(result.error || 'Failed to search categories by term');
      }
    } catch (error) {
      console.error('Error searching categories by term:', error);
      return { success: false, error: error.message };
    }
  }

  /**
   * Check if a related data definition name is unique
   * @param {number} id - ID of the item (0 for new items)
   * @param {string} name - Name to check
   * @param {string} relateClassName - Related class name
   * @returns {Promise<Object>} API response
   */
  async isNameUnique(id, name, relateClassName) {
    try {
      const response = await fetch(`${this.baseUrl}/IsRelatedDataDefNameUniqueJson`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          id: id.toString(),
          name: name,
          relateClassName: relateClassName
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      return result;
    } catch (error) {
      console.error('Error checking name uniqueness:', error);
      return { success: false, error: error.message };
    }
  }

  /**
   * Get field options (DataTypes, Domains) - static options that rarely change
   * @param {string} domainCode - Optional domain code for default value options
   * @returns {Promise<Object>} API response with options
   */
  async getFieldOptions(domainCode = null) {
    try {
      const params = new URLSearchParams();
      if (domainCode) params.append('domainCode', domainCode);
      
      const response = await fetch(`${this.baseUrl}/GetFieldOptionsApi`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: params
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      
      if (result.success) {
        return { success: true, ...result };
      } else {
        throw new Error(result.error || 'Failed to get field options');
      }
    } catch (error) {
      console.error('Error getting field options:', error);
      return { success: false, error: error.message };
    }
  }
}

// Create and export singleton instance
const dataApi = new DataApiService();
export default dataApi;
